CREATE OR REPLACE FUNCTION customers.api_path_delete(_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check if exist
    IF NOT EXISTS (SELECT * FROM api_path WHERE id = _id) THEN
        RAISE EXCEPTION 'No api_path with id % found', _id USING ERRCODE = 'T1AZ0';
    end if;

    -- delete api paths
    DELETE FROM api_path_page WHERE api_path_id = _id;

    -- delete page
    DELETE FROM api_path WHERE id = _id;

END;
$function$

CREATE OR REPLACE FUNCTION customers.api_path_get(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    pages json;
    result json;
BEGIN

    -- if page not found -> error
    IF NOT EXISTS (SELECT * FROM api_path WHERE id = _id) THEN
        RAISE EXCEPTION 'No api_path with id % found', _id USING ERRCODE = 'T1AZ0';
    end if;

    SELECT into pages json_agg(x) FROM (
        SELECT page_name from api_path_page WHERE api_path_id = _id
    ) x;

    -- get global json
    SELECT INTO result json_agg(x) -> 0 FROM (
         SELECT api_path.*, pages FROM api_path WHERE id = _id LIMIT 1
     ) x;

    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION customers.api_path_get_all(_search_struct json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tmp json[];
BEGIN
    SELECT array (
        SELECT api_path_get(p.id)
        FROM api_path p
        WHERE path LIKE concat('%', _search_struct->>'search_string', '%')
        ORDER BY p.path
    ) into tmp;
    RETURN to_json(tmp);
END;
$function$

CREATE OR REPLACE FUNCTION customers.api_path_get_or_insert(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _api_path_id bigint;
BEGIN

    IF NOT EXISTS(SELECT * FROM api_path WHERE method = json_data->> 'method' AND path = json_data ->> 'path') THEN
        SELECT api_path_new(json_data) INTO _api_path_id;
    ELSE
        SELECT id FROM api_path WHERE method = json_data->> 'method' AND path = json_data ->> 'path' INTO _api_path_id;
    end if;

    RETURN _api_path_id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.api_path_new(json_data json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _id bigint;
BEGIN
    -- check already exists
    IF EXISTS(SELECT * FROM api_path WHERE path = json_data->>'path' AND method = json_data->>'method') THEN
        RAISE EXCEPTION 'ApiPath with path = % and method = % already exists', json_data ->> 'path', json_data->>'method' USING ERRCODE = 'T1AZ1';
    end if;

    INSERT INTO api_path (path, method) VALUES (json_data->>'path', json_data->>'method') RETURNING id INTO _id;
    RETURN _id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.auto_add_pages_from_page()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN

    IF NEW.auto_add THEN
        -- add to role all the
        INSERT INTO customers.role_page (role_id, page_name)
        SELECT
            id,
            NEW.name
        FROM customers.role
        ON CONFLICT DO NOTHING;
    END IF;

    IF OLD.auto_add IS TRUE AND NEW.auto_add IS NOT TRUE THEN

        -- delete from role <-> page the
        RAISE NOTICE 'page % changed from auto_add=% to %', NEW.name, OLD.auto_add, NEW.auto_add;
        DELETE FROM customers.role_page
        WHERE page_name = NEW.name;
    END IF;

    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION customers.biometric_request_new_ext(json_data json, _caller_customer_id bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
_request_id bigint;
BEGIN

    -- check user_struct exists
    IF NOT EXISTS (SELECT 1 FROM customers.user_struct WHERE id = (json_data->>'user_struct_id')::bigint AND customer_id = _caller_customer_id) THEN
        RAISE EXCEPTION 'No user_struct with id % found for customer %', (json_data->>'user_struct_id')::bigint, _caller_customer_id USING ERRCODE = 'T5AZ0';
    END IF;

    -- check admin exists
    IF NOT EXISTS (SELECT 1 FROM customers.user_struct WHERE id = (json_data->>'admin_user_struct_id')::bigint AND customer_id = _caller_customer_id) THEN
        RAISE EXCEPTION 'No admin user_struct with id % found for customer %', (json_data->>'admin_user_struct_id')::bigint, _caller_customer_id USING ERRCODE = 'T5AZ0';
    END IF;

        -- insert into biometric_request
    INSERT INTO customers.biometric_request (
        user_struct_id,
        admin_user_struct_id,
        request_type,
        request_source,
        customer_id
    ) VALUES (
         (json_data->>'user_struct_id')::bigint,
         (json_data->>'admin_user_struct_id')::bigint,
         (json_data->>'request_type')::request_type_enum,
         'external'::request_source_enum,
         _caller_customer_id
     )
    RETURNING id INTO _request_id;

    RETURN _request_id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.contact_get(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _contact json;
BEGIN

    -- raise exception if not found
    IF NOT EXISTS(SELECT * FROM customers.contact WHERE id = _id) THEN
        RAISE EXCEPTION 'No contact with id % found', _id USING ERRCODE = 'T9AZ0';
    end if;

    -- get contact
    SELECT INTO _contact json_agg(x) -> 0 FROM (
        SELECT c.id,ct.name as type,c.name,c.maintenance_notification,c.marketing_notification,c.value,c.user_struct_id FROM customers.contact c LEFT JOIN customers.contact_type ct ON c.type_id = ct.id WHERE c.id = _id LIMIT 1
    ) x;

    -- return json
    RETURN _contact;

END;
$function$

