CREATE OR REPLACE FUNCTION customers.customer_get_all(_filter_struct json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _customers json[];
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _filter_struct ->> 'search_string', '%') INTO _search_pattern;

    SELECT ARRAY(
        SELECT customers.get_customer_by_id(id) FROM customers.customer
           WHERE name LIKE _search_pattern
           AND ( _filter_struct ->> 'customer_group_id' IS NULL OR group_id = (_filter_struct ->> 'customer_group_id')::bigint)
           AND ( _filter_struct ->> 'state_id' IS NULL OR state_id = (_filter_struct ->> 'state_id')::bigint)
           ORDER BY name
    ) INTO _customers;

    RETURN to_json(_customers);


END;
$function$

CREATE OR REPLACE FUNCTION customers.customer_group_get(_cg_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _vars json;
BEGIN

    -- check cg exists
    IF NOT EXISTS(SELECT 1 FROM customers.customer_group WHERE id = _cg_id) THEN
        RAISE EXCEPTION 'No customer_group with id % found', _cg_id USING ERRCODE = 'T2BZ0';
    end if;

    -- get variables in json array
    SELECT json_agg(x) FROM (SELECT action, resource FROM customers.customer_group_variable WHERE customer_group_id = _cg_id )x INTO _vars;

    -- to_json()

    RETURN json_agg(x)->0 FROM(
        SELECT *
             ,_vars as variables
        FROM customers.customer_group WHERE id = _cg_id
    )x;
END;
$function$

CREATE OR REPLACE FUNCTION customers.customer_group_get_all(_filter_struct json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _customer_groups json[];
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _filter_struct ->> 'search_string', '%') INTO _search_pattern;

    SELECT ARRAY(
                   SELECT customers.customer_group_get(id) FROM customer_group
                   WHERE name LIKE _search_pattern
                     AND ( _filter_struct ->> 'is_partner' IS NULL OR is_partner = (_filter_struct ->> 'is_partner')::bool)
                     AND ( _filter_struct ->> 'is_default' IS NULL OR is_default = (_filter_struct ->> 'is_default')::bool)
                   ORDER BY id
           ) INTO _customer_groups;

    RETURN to_json(_customer_groups);


END;
$function$

CREATE OR REPLACE FUNCTION customers.customer_group_update(_json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _var json;
BEGIN

    -- check if exist customer
    IF NOT EXISTS (SELECT 1 FROM customers.customer_group WHERE id = (_json_data ->> 'id')::bigint) THEN
        RAISE EXCEPTION 'No customer_group with id % found', (_json_data ->> 'id')::bigint USING ERRCODE = 'T2BZ0';
    end if;

    -- update name
    IF _json_data ->> 'name' IS NOT NULL THEN
        UPDATE customers.customer_group SET name = _json_data ->> 'name' WHERE id = (_json_data ->> 'id')::bigint;
    END IF;

    IF _json_data ->> 'is_default' IS NOT NULL THEN

        UPDATE customers.customer_group SET is_default = (_json_data ->> 'is_default')::bool WHERE id = (_json_data ->> 'id')::bigint;
    END IF;

    IF _json_data ->> 'is_partner' IS NOT NULL THEN

        UPDATE customers.customer_group SET is_partner = (_json_data ->> 'is_partner')::bool WHERE id = (_json_data ->> 'id')::bigint;
    END IF;

    -- delete and replace vars
    if (_json_data ->> 'variables') IS NOT NULL THEN

        -- delete old
        DELETE FROM customers.customer_group_variable WHERE customer_group_id = (_json_data ->> 'id')::bigint;

        -- insert new
        for _var in select * from json_array_elements(_json_data -> 'variables')
            loop

                INSERT INTO customers.customer_group_variable (customer_group_id, resource, action) VALUES
                    (
                        (_json_data ->> 'id')::bigint,
                        _var ->> 'resource',
                        _var ->> 'action'
                    );
            end loop;

    end if;

END;
$function$

CREATE OR REPLACE FUNCTION customers.customer_update(_json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _var json;
BEGIN

    -- check if exist customer
    IF NOT EXISTS (SELECT 1 FROM customers.customer WHERE id = (_json_data ->> 'id')::bigint) THEN
        RAISE EXCEPTION 'No customer with id % found', (_json_data ->> 'id')::bigint USING ERRCODE = 'T1BZ0';
    end if;

    -- update name
    IF _json_data ->> 'name' IS NOT NULL THEN
        UPDATE customers.customer SET name = _json_data ->> 'name' WHERE id = (_json_data ->> 'id')::bigint;
    END IF;

    -- update group_id
    IF _json_data ->> 'group_id' IS NOT NULL THEN

        -- check if exist customer_group
        IF NOT EXISTS (SELECT 1 FROM customers.customer_group WHERE id = (_json_data ->> 'group_id')::bigint) THEN
            RAISE EXCEPTION 'No customer_group with id % found', (_json_data ->> 'group_id')::bigint USING ERRCODE = 'T2BZ0';
        end if;

        UPDATE customers.customer SET group_id = (_json_data ->> 'group_id')::bigint WHERE id = (_json_data ->> 'id')::bigint;
    END IF;

    -- update group_id
    IF _json_data ->> 'state_id' IS NOT NULL THEN

        -- check if exist customer_group
        IF NOT EXISTS (SELECT 1 FROM customers.customer_state WHERE id = (_json_data ->> 'state_id')::bigint) THEN
            RAISE EXCEPTION 'No customer_state with id % found', (_json_data ->> 'state_id')::bigint USING ERRCODE = 'T1BZ3';
        end if;

        UPDATE customers.customer SET state_id = (_json_data ->> 'state_id')::bigint WHERE id = (_json_data ->> 'id')::bigint;
    END IF;

    -- delete and replace vars
    if (_json_data ->> 'variables') IS NOT NULL THEN

        -- delete old
        DELETE FROM customers.customer_variable WHERE customer_id = (_json_data ->> 'id')::bigint;

        -- insert new
        for _var in select * from json_array_elements(_json_data -> 'variables')
        loop

            INSERT INTO customers.customer_variable (customer_id, resource, action) VALUES
                (
                    (_json_data ->> 'id')::bigint,
                    _var ->> 'resource',
                    _var ->> 'action'
                );
        end loop;

    end if;

END;
$function$

CREATE OR REPLACE FUNCTION customers.delete_biometric_requests_on_email_null()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- Check if primary_email is being set to NULL
    IF NEW.primary_email IS NULL AND OLD.primary_email IS NOT NULL THEN
        DELETE FROM customers.biometric_request
        WHERE user_struct_id = OLD.id;
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION customers.get_customer_by_id(_customer_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _customer customers.customer%rowtype;
    _customer_state customers.customer_state%rowtype;
    _customer_group json;
    _vars json;
    _language varchar;
BEGIN

    IF NOT EXISTS(SELECT * FROM customers.customer WHERE id = _customer_id)THEN
        RAISE EXCEPTION 'Invalid customer_id: %', _customer_id USING ERRCODE = 'T1BZ3';
    end if;

    SELECT * FROM customers.customer WHERE id = _customer_id LIMIT 1 INTO _customer;

    SELECT cs.* FROM customers.customer_state cs INNER JOIN customers.customer c ON cs.id = c.state_id WHERE c.id = _customer_id LIMIT 1 INTO _customer_state;

    IF NOT EXISTS(SELECT * FROM customers.customer_group WHERE id = _customer.group_id)THEN
        RAISE EXCEPTION 'MECHAERROR: Nonexistent customer_group_id: % from customer w/ id: %', _customer.group_id, _customer_id USING ERRCODE = 'T2BZ4';
    end if;

    -- get variables in json array
    SELECT json_agg(x) FROM (SELECT action, resource FROM customers.customer_variable WHERE customer_id = _customer_id )x INTO _vars;

    SELECT json_agg(x)->0 FROM (
        SELECT * FROM customers.customer_group WHERE id = _customer.group_id LIMIT 1
    )x INTO _customer_group;

    SELECT COALESCE((
        CASE
            WHEN LOWER(lingua) LIKE 'ita%' THEN 'it'
            WHEN LOWER(lingua) LIKE 'eng%' THEN 'en'
            WHEN LOWER(lingua) LIKE 'ing%' THEN 'en'
            ELSE 'it'
            END
    ), 'it')
    FROM loader.erp_anagrafiche_clienti WHERE numero_azienda = _customer_id INTO _language;

    -- handle edge case where no customer is found in erp_anagrafiche_clienti
    IF _language IS NULL THEN
        _language = 'it';
    end if;

    RETURN json_agg(x)->0 FROM (
        SELECT _customer.*, _customer_group as customer_group, _customer_state as state, _vars as variables, _language as language
    )x;

END;
$function$

CREATE OR REPLACE FUNCTION customers.get_customer_disable_biometric_user_ids(_customer_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    result JSONB := '[]'::jsonb;
    r RECORD;
    br_json JSONB;
BEGIN
    -- Validate customer exists
    IF NOT EXISTS (SELECT 1 FROM customers.customer WHERE id = _customer_id) THEN
        RAISE EXCEPTION 'Customer not found: %', _customer_id
            USING ERRCODE = 'T1BZ0';
    END IF;

    FOR r IN (SELECT id FROM customers.user_struct WHERE customer_id = _customer_id) LOOP
        BEGIN
            br_json := customers.get_latest_biometric_request(r.id);

            -- Include only if last request is 'activation'
            IF br_json->>'request_type' = 'activation' THEN
                result := result || to_jsonb(r.id);
            END IF;

        EXCEPTION
            WHEN SQLSTATE 'T8AZ0' THEN
                NULL; -- Ignore users with no biometric request
        END;
    END LOOP;

    RETURN result::json;
END;
$function$

CREATE OR REPLACE FUNCTION customers.get_customer_enable_biometric_user_ids(_customer_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
result JSONB := '[]'::jsonb;
    r RECORD;
    br_json JSONB;
BEGIN
    IF NOT EXISTS (SELECT 1 FROM customers.customer WHERE id = _customer_id) THEN
        RAISE EXCEPTION 'Customer not found: %', _customer_id
            USING ERRCODE = 'T1BZ0';
    END IF;

    FOR r IN (SELECT id FROM customers.user_struct WHERE customer_id = _customer_id) LOOP
        BEGIN

            br_json := customers.get_latest_biometric_request(r.id);

            IF br_json->>'request_type' = 'deactivation'
                AND br_json->>'request_source' = 'internal' THEN
                result := result || to_jsonb(r.id);
            END IF;

        EXCEPTION 
            WHEN SQLSTATE 'T8AZ0' THEN
                NULL;
        END;
    END LOOP;

    RETURN result::json;
END;
$function$

CREATE OR REPLACE FUNCTION customers.get_customer_group_id(customer_id integer)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
declare
    l_context text;
    result int;
begin
    set search_path = pg_catalog,pg_temp;

    -- PRE CHECK
    -- check if customer with the requested customer_id exists, if not return false
    if ( not exists ( select c.id from customers.customer c where c.id = customer_id ) ) then 
        RAISE EXCEPTION 'Customer with ID: % does not exist', customer_id USING ERRCODE = 'C1CE2';
    end if;

    select into result ( select c.group_id from customers.customer c where c.id = customer_id );

    return result;

    EXCEPTION
        WHEN SQLSTATE 'C1CE2' THEN RAISE EXCEPTION 'Customer with ID: % does not exist', customer_id USING ERRCODE = 'C1CE2';
        WHEN OTHERS THEN
            GET STACKED DIAGNOSTICS l_context = PG_EXCEPTION_CONTEXT;
            RAISE EXCEPTION 'Error: %, %', SQLERRM, l_context;
            RETURN -1;

end;

    $function$

CREATE OR REPLACE FUNCTION customers.my_data_get(_email character varying, _log_in boolean)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
    _customer_id bigint;
    _state json;
    _role json;
    _customer json;
    _variables json;
    _disabled boolean;
BEGIN

    -- check user -> if true -> user has no user_structs and is deleted
    -- this should never happen, but better safe than sorry
    IF customers.user_check(_email) THEN
        RETURN NULL;
    end if;

    -- check if user exists
    IF NOT EXISTS (SELECT * FROM customers."user" WHERE email = _email) THEN
        RAISE EXCEPTION 'No user_struct with email % found', _email USING ERRCODE = 'T5AZ0';
    end if;

    -- get active user struct id
    SELECT id FROM customers."user" u INNER JOIN customers.user_struct us ON u.active_user_struct_id = us.id WHERE email = _email INTO _user_struct_id;

    SELECT customer_id from customers.user_struct us WHERE us.id = _user_struct_id INTO _customer_id;

    -- log login
    IF _log_in THEN
        UPDATE customers.user_struct SET last_login = NOW() WHERE id = _user_struct_id;
    end if;

    SELECT json_agg(x) -> 0 FROM (
        SELECT s.* FROM customers.user_struct us INNER JOIN customers.user_state s ON us.state_id = s.id WHERE us.id = _user_struct_id
    )x
    INTO _state;

    SELECT NOT (((_state->>'enabled')::bool ) AND (SELECT cs.enabled FROM customers.customer c INNER JOIN customers.customer_state cs on c.state_id = cs.id WHERE c.id = _customer_id)) INTO _disabled;
    RAISE NOTICE '_disabled = ( % && % ) = %', NOT((_state->>'enabled')::bool), (SELECT NOT(cs.enabled) FROM customers.customer c INNER JOIN customers.customer_state cs on c.state_id = cs.id WHERE c.id = _customer_id), _disabled;


    SELECT customers.get_customer_by_id(_customer_id) INTO _customer;

    -- get role
    SELECT customers.role_build_json_ext(role_id, _customer_id, _disabled) FROM customers.user_struct us WHERE us.id = _user_struct_id INTO _role;

    -- get variables
    SELECT customers.variable_get_by_user_struct(_user_struct_id) INTO _variables;

    -- join in json
    RETURN json_agg(x) -> 0 FROM (
       SELECT us.*, _role as role, _variables as variables, _customer as customer, _state as state FROM customers.user_struct us WHERE us.id = _user_struct_id LIMIT 1
    ) x;
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_add_api_path(_page_name character varying, _api_path_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check if page exists
    IF NOT EXISTS (SELECT * FROM customers.page WHERE name = _page_name) THEN
        RAISE EXCEPTION '[page_add_api_path] No page with name % found', _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- check api path exists
    IF NOT EXISTS (SELECT * FROM customers.api_path WHERE id = _api_path_id) THEN
        RAISE EXCEPTION '[page_add_api_path] No api_path with id % found', _api_path_id USING ERRCODE = 'T1AZ0';
    END IF;

    -- check already exists link
    IF EXISTS (SELECT * FROM customers.api_path_page WHERE page_name = _page_name AND api_path_id = _api_path_id) THEN
        RAISE EXCEPTION '[page_add_api_path] ApiPath w/ id = % is already assigned to page %s', _api_path_id, _page_name USING ERRCODE = 'T2AZ1';
    end if;

    INSERT INTO customers.api_path_page (page_name, api_path_id) VALUES (_page_name, _api_path_id);
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_delete(_name character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check if exist
    IF NOT EXISTS (SELECT * FROM customers.page WHERE name = _name) THEN
        RAISE EXCEPTION '[page_delete] No page with name % found', _name USING ERRCODE = 'T2AZ0';
    end if;

    -- delete api paths
    DELETE FROM customers.api_path_page WHERE page_name = _name;

    -- delete link to cg
    DELETE FROM customers.page_customer_group WHERE page_name = _name;

    -- delete page
    DELETE FROM customers.page WHERE name = _name;

END;
$function$

CREATE OR REPLACE FUNCTION customers.page_get_all_ext(_customer_id bigint, _search_string character varying)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tmp json[];
    _customer_group_id bigint;
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _search_string, '%') INTO _search_pattern;
    SELECT group_id FROM customers.customer WHERE id = _customer_id INTO _customer_group_id;

    SELECT array(
                SELECT
                    customers.page_get_ext(p.name, _customer_group_id)
                FROM customers.page p
                    LEFT JOIN customers.page_customer_group pcg ON p.name = pcg.page_name
                WHERE p.only_selectable_by_cdlan = false
                    AND pcg.customer_group_id = _customer_group_id
                    AND p.name LIKE _search_pattern
                ORDER BY p.name
           )
    into tmp;
    RETURN to_json(tmp);
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_get_all_sudo(_search_struct json)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tmp json[];
    _group_id bigint;
BEGIN

    IF (_search_struct->>'customer_id' IS NULL)
    THEN
        SELECT array (SELECT customers.page_get_sudo(p.name)
            FROM customers.page p
            WHERE p.name LIKE concat('%', _search_struct->>'search_string', '%')
                AND (_search_struct->>'customer_group_id' IS NULL OR (_search_struct->>'customer_group_id')::bigint IN (SELECT customer_group_id FROM customers.page_customer_group pcg WHERE pcg.page_name = p.name))
                AND (_search_struct->>'selectable_only_by_cdlan' IS NULL OR p.only_selectable_by_cdlan = (_search_struct->>'selectable_only_by_cdlan')::bool)
            ORDER BY p.name
        ) into tmp;

    ELSE

        SELECT group_id FROM customers.customer WHERE id = (_search_struct->>'customer_id')::bigint INTO _group_id;

        IF _group_id IS NULL THEN
            RAISE EXCEPTION 'customer not found for customer_id %', (_search_struct->>'customer_id')::bigint USING ERRCODE = 'T1BZ0';
        END IF;

        SELECT array (SELECT customers.page_get_sudo(p.name)
            FROM customers.page p
            WHERE p.name LIKE concat('%', _search_struct->>'search_string', '%')
                AND _group_id IN (SELECT customer_group_id FROM customers.page_customer_group pcg WHERE pcg.page_name = p.name)
                AND (_search_struct->>'selectable_only_by_cdlan' IS NULL OR p.only_selectable_by_cdlan = (_search_struct->>'selectable_only_by_cdlan')::bool)
            ORDER BY p.name
        ) into tmp;
    end if;

    RETURN to_json(tmp);
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_get_by_role_id_ext(_role_id bigint, _customer_group_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tmp json[];
BEGIN

    SELECT array (
                   SELECT customers.page_get_ext(name, _customer_group_id)
                   FROM customers.page_get_by_role_id_table_ext(_role_id, _customer_group_id)
                    ORDER BY name
           ) into tmp;

    RETURN to_json(tmp);
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_get_by_role_id_sudo(_role_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    tmp json[];
BEGIN

    SELECT array (
                   SELECT customers.page_get_sudo(name)
