CREATE OR REPLACE FUNCTION customers.page_get_ext(_name character varying, _customer_group_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    paths json;
    _available_to_cg bigint[];
BEGIN

    -- check page exists and user can access it
    IF NOT EXISTS (SELECT * FROM customers.page p LEFT JOIN customers.page_customer_group pcg ON p.name = pcg.page_name WHERE p.name = _name AND pcg.customer_group_id = _customer_group_id) THEN
        RAISE EXCEPTION '[page_get_ext] No page with name % found', _name USING ERRCODE = 'T2AZ0';
    end if;

    -- get resources as json array
    SELECT into paths json_agg(x) FROM (
       SELECT ap.path, ap.method from customers.api_path ap INNER JOIN customers.api_path_page app ON ap.id = app.api_path_id WHERE page_name = _name
    ) x;

    SELECT INTO _available_to_cg ARRAY (
        SELECT _customer_group_id
    );

    -- get global json
    RETURN json_agg(x) -> 0 FROM (
        SELECT page.*, paths, to_json(_available_to_cg) as available_to_cg FROM customers.page WHERE name = _name LIMIT 1
    ) x;

END;
$function$

