CREATE OR REPLACE FUNCTION customers.page_new(json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _cg_id bigint;
    _res json;
    _api_path_id bigint;
    _auto_add boolean DEFAULT FALSE;
    _only_selectable_by_cdlan boolean DEFAULT FALSE;
BEGIN

    -- check already exists
    IF EXISTS (SELECT * FROM customers.page WHERE name = json_data ->> 'name') THEN
        RAISE EXCEPTION '[page_new] Page with name % already exists', json_data ->> 'name' USING ERRCODE = 'T2AZ1';
    end if;

    IF json_data ->> 'only_selectable_by_cdlan' IS NOT NULL THEN
        _only_selectable_by_cdlan = (json_data ->> 'only_selectable_by_cdlan')::boolean;
    end if;

    IF json_data ->> 'auto_add' IS NOT NULL AND (json_data ->> 'auto_add')::boolean IS TRUE THEN
        _auto_add = (json_data ->> 'auto_add')::boolean;

        -- if auto_add use only_selectable_by_cdlan to hide it from selectable pages
        _only_selectable_by_cdlan = true;
    end if;

    -- create page
    IF _only_selectable_by_cdlan IS TRUE THEN

        INSERT INTO customers.page (name, only_selectable_by_cdlan, auto_add) values (json_data ->> 'name', TRUE, _auto_add);
    ELSE

        INSERT INTO customers.page (name, auto_add) values (json_data ->> 'name', _auto_add);
    end if;

    if (json_data->>'available_to_cg') IS NOT NULL THEN
        FOR _cg_id IN SELECT * FROM json_array_elements(json_data->'available_to_cg')
        LOOP
            INSERT INTO customers.page_customer_group (page_name, customer_group_id) VALUES (json_data ->> 'name', _cg_id);
        END LOOP;
    end if;

    -- create res access
    if (json_data->>'paths') IS NOT NULL THEN

        for _res in select * from json_array_elements(json_data -> 'paths')
            loop
                SELECT customers.api_path_get_or_insert(_res) INTO _api_path_id;
                PERFORM customers.page_add_api_path(json_data ->> 'name', _api_path_id);
            end loop;
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_rm_api_path(_page_name character varying, _api_path_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check if page exists
    IF NOT EXISTS (SELECT * FROM customers.page WHERE name = _page_name) THEN
        RAISE EXCEPTION '[page_rm_api_path] No page with name % found', _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- check api path exists
    IF NOT EXISTS (SELECT * FROM customers.api_path WHERE id = _api_path_id) THEN
        RAISE EXCEPTION '[page_rm_api_path] No api_path with id % found', _api_path_id USING ERRCODE = 'T1AZ0';
    END IF;

    -- check already exists link
    IF NOT EXISTS (SELECT * FROM customers.api_path_page WHERE page_name = _page_name AND api_path_id = _api_path_id) THEN
        RAISE EXCEPTION '[page_rm_api_path] ApiPath w/ id = % is not assigned to page %s', _api_path_id, _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- delete
    DELETE FROM customers.api_path_page WHERE page_name = _page_name AND api_path_id = _api_path_id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.page_update(json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _path json;
    _cg_id bigint;
    _api_path_id bigint;
BEGIN

    -- check if exist
    IF NOT EXISTS (SELECT * FROM customers.page WHERE name = json_data ->> 'name') THEN
        RAISE EXCEPTION '[page_update] No page with name % found', json_data ->> 'name' USING ERRCODE = 'T2AZ0';
    end if;

    -- update only_selectable_by_cdlan
    IF json_data ->> 'only_selectable_by_cdlan' IS NOT NULL THEN
        UPDATE customers.page SET only_selectable_by_cdlan = (json_data ->> 'only_selectable_by_cdlan')::bool WHERE name = json_data ->> 'name';
    END IF;

    IF json_data ->> 'auto_add' IS NOT NULL THEN
        UPDATE customers.page SET auto_add = (json_data ->> 'auto_add')::boolean WHERE name = json_data ->> 'name';

        IF (json_data ->> 'auto_add')::boolean IS TRUE THEN
            UPDATE customers.page SET only_selectable_by_cdlan = true WHERE name = json_data ->> 'name';
        end if;
    end if;



    -- create res access if exists
    IF (json_data->'paths') IS NOT NULL THEN

        -- delete old
        DELETE FROM customers.api_path_page WHERE page_name = json_data ->> 'name';

        -- insert new
        for _path in select * from json_array_elements(json_data -> 'paths')
        loop
            SELECT customers.api_path_get_or_insert(_path) INTO _api_path_id;
            PERFORM customers.page_add_api_path(json_data ->> 'name', _api_path_id);
        end loop;
    END IF;

    -- if available_to_cg not null -> override
    IF (json_data->'available_to_cg') IS NOT NULL THEN

        -- delete old
        DELETE FROM customers.page_customer_group WHERE page_name = json_data ->> 'name';

        -- insert new
        FOR _cg_id IN SELECT * FROM json_array_elements(json_data->'available_to_cg')
        LOOP
            INSERT INTO customers.page_customer_group (page_name, customer_group_id) VALUES (json_data ->> 'name', _cg_id);
        END LOOP;
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION customers.preference_get(_user_struct_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check preference exists for user
    IF NOT EXISTS (SELECT * FROM preference WHERE user_struct_id = _user_struct_id) THEN
        RAISE EXCEPTION 'Preference not found for for user %', _user_struct_id USING ERRCODE = 'T6AZ0';
    end if;

    RETURN json_agg(x) -> 0 FROM (
        SELECT preference.*, us.language FROM preference INNER JOIN user_struct us ON us.id = preference.user_struct_id WHERE user_struct_id = _user_struct_id LIMIT 1
    ) x;
END;
$function$

CREATE OR REPLACE FUNCTION customers.preference_new(json_data json, _user_struct_id bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _preference_id bigint;
BEGIN

    -- check user_struct is valid
    IF NOT EXISTS(SELECT * FROM user_struct WHERE id = _user_struct_id) THEN
        RAISE EXCEPTION 'No user found for id %', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- check does not already exist preference for user
    IF EXISTS (SELECT * FROM preference WHERE user_struct_id = _user_struct_id) THEN
        RAISE EXCEPTION 'Preference already exists for user %', _user_struct_id USING ERRCODE = 'T6AZ1';
    end if;

    UPDATE user_struct SET language = json_data ->> 'language' WHERE id = _user_struct_id;

    -- create preference
    INSERT INTO preference (user_struct_id, avatar_link, json_preferences) values (_user_struct_id, json_data ->> 'avatar_link', (json_data ->> 'json_preferences')::json) RETURNING id INTO _preference_id;

    RETURN _preference_id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.preference_update(json_data json, _user_struct_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check user_struct is valid
    IF NOT EXISTS(SELECT * FROM user_struct WHERE id = _user_struct_id) THEN
        RAISE EXCEPTION 'No user_struct found for id %', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- check preference exists for user
    IF NOT EXISTS (SELECT * FROM preference WHERE user_struct_id = _user_struct_id) THEN
        RAISE EXCEPTION 'Preference not found for for user %', _user_struct_id USING ERRCODE = 'T6AZ0';
    end if;

    -- update language
    IF json_data ->> 'language' IS NOT NULL THEN
        UPDATE user_struct SET language = json_data ->> 'language' WHERE id = _user_struct_id;
    END IF;

    -- update avatar_link
    IF json_data ->> 'avatar_link' IS NOT NULL THEN
        UPDATE preference SET avatar_link = json_data ->> 'avatar_link' WHERE user_struct_id = _user_struct_id;
    END IF;

    -- update json_preferences
    IF json_data ->> 'json_preferences' IS NOT NULL THEN
        UPDATE preference SET json_preferences = (json_data ->> 'json_preferences')::json WHERE user_struct_id = _user_struct_id;
    END IF;

END;
$function$

CREATE OR REPLACE FUNCTION customers.role_add_page_ext(_role_id bigint, _page_name character varying, _caller_customer_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _page customers.page%rowtype;
    _role customers.role%rowtype;
    _customer_group_id bigint;
    _customer json;
BEGIN

    SELECT customers.get_customer_by_id(_caller_customer_id) INTO _customer;
    _customer_group_id = (((_customer->>'customer_group')::json)->>'id')::bigint;

    RAISE NOTICE 'SELECT * FROM customers.page p LEFT JOIN customers.page_customer_group pcg on p.name = pcg.page_name WHERE p.name = % AND only_selectable_by_cdlan = false AND pcg.customer_group_id = %', _page_name, _customer_group_id;

    -- check page exists and user can see it
    IF NOT EXISTS (SELECT * FROM customers.page p LEFT JOIN customers.page_customer_group pcg on p.name = pcg.page_name WHERE p.name = _page_name AND only_selectable_by_cdlan = false AND pcg.customer_group_id = _customer_group_id) THEN
        RAISE EXCEPTION 'No page with name % found', _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- check role exists and caller can access
    IF NOT EXISTS (SELECT * FROM customers.role WHERE id = _role_id AND customer_id = _caller_customer_id) THEN
        RAISE EXCEPTION 'No role with id % found', _role_id USING ERRCODE = 'T3AZ0';
    end if;

    -- check mapping does not already exist
    IF EXISTS (SELECT * FROM customers.role_page rp WHERE rp.page_name = _page_name AND rp.role_id = _role_id) THEN
        RAISE EXCEPTION 'Page with name % already exist for role %', _page_name, _role_id USING ERRCODE = 'T1AZ1';
    end if;

    -- check if page is protected and role is default
    SELECT * FROM customers.page p WHERE p.name = _page_name INTO _page;
    SELECT * FROM customers.role WHERE id = _role_id INTO _role;

    IF (_page.only_selectable_by_cdlan = true OR NOT EXISTS (SELECT * FROM customers.page_customer_group WHERE page_name = _page_name AND customer_group_id = _customer_group_id)) THEN
        RAISE EXCEPTION 'Page with name % is protected and cannot be assigned to customer role %', _page_name, _role_id USING ERRCODE = 'T1AZ2';
    end if;

    -- insert mapping
    INSERT INTO customers.role_page (role_id, page_name) VALUES (_role_id, _page_name);

END;
$function$

