CREATE OR REPLACE FUNCTION customers.role_build_json_ext(_id bigint, _caller_customer_id bigint, _disabled boolean)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    pages json[];
    _user_count int;
    _customer_group_id bigint;
    _customer json;
    result json;
BEGIN

    SELECT customers.get_customer_by_id(_caller_customer_id) INTO _customer;
    _customer_group_id = (((_customer->>'customer_group')::json)->>'id')::bigint;

    IF NOT _disabled THEN
        -- get pages as json array
        SELECT array(
                       SELECT customers.page_get_ext(p.name, _customer_group_id)
                       FROM customers.role_page rp
                                LEFT JOIN customers.page p ON rp.page_name = p.name
                                LEFT JOIN customers.page_customer_group pcg ON p.name = pcg.page_name
                       WHERE rp.role_id = _id
                         -- AND p.only_selectable_by_cdlan = false
                         AND pcg.customer_group_id = _customer_group_id
               ) into pages;
    END IF;

    SELECT COUNT(*) FROM customers.user_struct WHERE role_id = _id AND customer_id = _caller_customer_id INTO _user_count;

    -- compose global json
    SELECT INTO result json_agg(x) -> 0 FROM (
        SELECT id, name, customer_id, color, pages, _user_count as user_count FROM customers.role WHERE id = _id LIMIT 1
    ) x;

    RETURN result;
END;
$function$

CREATE OR REPLACE FUNCTION customers.role_build_json_sudo(_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _pages json[];
    _result json;
    _user_count int;
BEGIN

    -- get pages as json array
    SELECT array(
        SELECT customers.page_get_sudo(p.name)
        FROM customers.role_page rp
        LEFT JOIN customers.page p ON rp.page_name = p.name
        WHERE rp.role_id = _id
    ) into _pages;

    -- compute count
    _user_count = (SELECT count(*) FROM customers.user_struct WHERE role_id = _id);

    -- compose global json
    SELECT INTO _result json_agg(x) -> 0 FROM (
        SELECT id, name, customer_id, color, _pages as pages, _user_count as user_count FROM customers.role WHERE id = _id LIMIT 1
    ) x;

    RETURN _result;
END;
$function$

