CREATE OR REPLACE FUNCTION customers.role_get_all_ext(_customer_id bigint, _search_string character varying, _only_customer_created boolean)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    roles json[];
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _search_string, '%') INTO _search_pattern;

    SELECT array(
        SELECT customers.role_build_json_ext(id, _customer_id, false)
        FROM customers.role
        WHERE name LIKE _search_pattern
          AND (
            (_only_customer_created AND customer_id = _customer_id)
            OR
            (NOT _only_customer_created AND (customer_id = _customer_id OR customer_id IS NULL))
          )
        ORDER BY name
    ) into roles;

    -- return
    RETURN to_json(roles);
END;
$function$

