CREATE OR REPLACE FUNCTION customers.role_new_ext(json_data json, _caller_customer_id bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _role_id bigint;
    _page_name varchar;
BEGIN

    -- check does not shadow default
    IF EXISTS (SELECT * FROM customers.role r WHERE r.name = json_data ->> 'name' AND r.customer_id IS NULL) THEN
        RAISE EXCEPTION 'Name % is already used by default role', json_data ->> 'name' USING ERRCODE = 'T3AZ1';
    end if;

    -- check already exists one with same (name, customer_id)
    IF EXISTS (SELECT * FROM customers.role r WHERE r.name = json_data ->> 'name' AND r.customer_id = _caller_customer_id ) THEN
        RAISE EXCEPTION 'Page with name % already exists', json_data ->> 'name' USING ERRCODE = 'T3AZ1';
    end if;

    -- Check if the color is NULL or an empty string
    IF json_data ->> 'color' IS NULL OR trim(json_data ->> 'color') = '' THEN
        RAISE EXCEPTION 'Color cannot be NULL or an empty string' USING ERRCODE = 'T3AZ3';
    END IF;

    -- create role
    INSERT INTO customers.role (name, customer_id, color) values (json_data ->> 'name', _caller_customer_id, json_data ->> 'color') RETURNING id INTO _role_id;

    -- add pages
    if (json_data->'pages') IS NOT NULL THEN

        for _page_name in select * from json_array_elements_text(json_data -> 'pages')
            loop

                PERFORM customers.role_add_page_ext(_role_id, _page_name, _caller_customer_id);
            end loop;
    END IF;

    RETURN _role_id;
END;
$function$

