    -- create role
    IF json_data->>'id' IS NOT NULL THEN

        -- if user provided also ID -> force ID
        INSERT INTO customers.role (id, name, customer_id, color) values ((role_new_sudo.json_data->>'id')::bigint, json_data ->> 'name', (json_data ->> 'customer_id')::bigint, json_data ->> 'color') RETURNING id INTO _role_id;
