CREATE OR REPLACE FUNCTION customers.role_rm_page_sudo(_role_id bigint, _page_name character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check page exists
    IF NOT EXISTS (SELECT * FROM customers.page p WHERE p.name = _page_name) THEN
        RAISE EXCEPTION 'No page with name % found', _page_name USING ERRCODE = 'T2AZ0';
    end if;

    -- check mapping exist
    IF NOT EXISTS (SELECT * FROM customers.role_page rp WHERE rp.page_name = _page_name AND rp.role_id = _role_id) THEN
        RAISE EXCEPTION 'Page with name % not bound to role %', _page_name, _role_id USING ERRCODE = 'T1AZ1';
    end if;

    -- delete page
    DELETE FROM customers.role_page rp WHERE rp.page_name = _page_name AND rp.role_id = _role_id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.role_update_ext(json_data json, _caller_customer_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _page varchar;
BEGIN

    -- check if exist and user can edit
    IF NOT EXISTS (SELECT * FROM customers.role WHERE id = (json_data ->> 'id')::bigint AND customer_id = _caller_customer_id) THEN
        RAISE EXCEPTION 'No role with id % found', (json_data ->> 'id')::bigint USING ERRCODE = 'T3AZ0';
    end if;

    -- update name
    IF json_data ->> 'name' IS NOT NULL THEN
        UPDATE customers.role SET name = json_data ->> 'name' WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update color
    IF json_data ->> 'color' IS NOT NULL THEN
        UPDATE customers.role SET color = json_data ->> 'color' WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- delete and replace pages if specified
    IF (json_data->'pages') IS NOT NULL THEN

        -- delete old
        DELETE FROM customers.role_page WHERE role_id = (json_data ->> 'id')::bigint;

        -- insert new
        for _page in select * from json_array_elements_text(json_data -> 'pages')
        loop

            PERFORM customers.role_add_page_ext((json_data ->> 'id')::bigint, _page, _caller_customer_id);
        end loop;

        -- insert autoadd
        for _page in select name from customers.page where auto_add is true
        loop
            INSERT INTO customers.role_page (role_id, page_name) VALUES ((json_data ->> 'id')::bigint, _page);
        end loop;
    END IF;
END;
$function$

