CREATE OR REPLACE FUNCTION customers.update_customer_credit()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
    -- First check if customer_credits record exists, if not create it
    IF NOT EXISTS (SELECT 1 FROM customers.customer_credits WHERE customer_id = NEW.customer_id) THEN
        INSERT INTO customers.customer_credits (customer_id, credit) VALUES (NEW.customer_id, 0);
    END IF;

    -- Then proceed with the credit update
    IF NEW.operation_sign = '+' THEN
        UPDATE customers.customer_credits
        SET credit = credit + NEW.amount
        WHERE customer_id = NEW.customer_id;
    ELSE
        UPDATE customers.customer_credits
        SET credit = credit - NEW.amount
        WHERE customer_id = NEW.customer_id;
    END IF;
    RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION customers.user_check(_email character varying)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
BEGIN

    RAISE NOTICE 'check_user';

    -- check if user exists
    IF NOT EXISTS(SELECT * FROM customers."user" WHERE email = _email) THEN

        RAISE NOTICE 'no user found in user table with email: %', _email;
        RETURN false;
    end if;

    -- if exist active_user_struct
    IF EXISTS(SELECT * FROM customers."user" u INNER JOIN customers.user_struct us ON u.active_user_struct_id = us.id WHERE email = _email AND us.primary_email = u.email) THEN

        RAISE NOTICE 'user has active user struct: %', (SELECT us.id FROM customers."user" u INNER JOIN customers.user_struct us ON u.active_user_struct_id = us.id WHERE email = _email);
        RETURN false; -- user has not been deleted
    end if;

    -- if user has no user_structs available -> delete user
    IF NOT EXISTS(SELECT id FROM customers.user_struct WHERE primary_email = _email) THEN

        RAISE NOTICE 'user has no available user_struct, deleting...' ;

        -- delete user bc it has no user_structs
        DELETE from customers."user" WHERE email = _email;

        RETURN true; --user has been deleted
    end if;

    -- if user has only soft deleted -> leave NULL
--     IF NOT EXISTS(SELECT id FROM customers.user_struct WHERE primary_email = _email AND state_id = 1) THEN
--
--         RAISE NOTICE 'user has only soft deleted user_structs, deleting...' ;
--
--         UPDATE customers."user" SET active_user_struct_id = NULL WHERE email = _email;
--         RETURN false; -- user has not been deleted
--     end if;

    -- choose first user_structs available
    SELECT id FROM customers.user_struct WHERE primary_email = _email LIMIT 1 INTO _user_struct_id;

    -- update
    UPDATE customers."user" SET active_user_struct_id = _user_struct_id WHERE email = _email;

    RETURN false; --user was not deleted
END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_add_contact(_user_struct_id bigint, _contact json)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _type_id bigint;
    _contact_id bigint;
BEGIN

    -- check if type exists
    IF NOT EXISTS(SELECT * FROM customers.contact_type WHERE name = _contact ->> 'type') THEN
        RAISE EXCEPTION 'No contact_type with name % found', _contact ->> 'type' USING ERRCODE = 'T8AZ0';
    end if;

    -- get type id
    SELECT * FROM customers.contact_type WHERE name = _contact ->> 'type' LIMIT 1 INTO _type_id;

    -- check contact not already exists
    IF EXISTS(SELECT * FROM customers.contact WHERE value = _contact ->> 'value' AND type_id = _type_id AND user_struct_id = _user_struct_id) THEN
        RAISE EXCEPTION 'contact already exists with name %', _contact ->> 'name' USING ERRCODE = 'T9AZ1';
    end if;

    -- create contact
    INSERT INTO customers.contact (type_id, name, user_struct_id, value, maintenance_notification, marketing_notification) VALUES (
        _type_id,
        _contact ->> 'name',
        _user_struct_id,
        _contact ->> 'value',
        (_contact ->> 'maintenance_notification')::bool,
        (_contact ->> 'marketing_notification')::bool
    ) RETURNING id INTO _contact_id;

    RETURN _contact_id;
END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_build_json_ext(_user_struct_id bigint, _caller_customer_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
_role json;
    _contacts json[];
    _res json;
    _state json;
    _enabled bool;
    _is_biometric bool;
    _latest_biometric_request jsonb;
    _biometric_info json;
BEGIN

    -- check if user_struct exists
    IF NOT EXISTS(
        SELECT *
        FROM customers.user_struct_view_ext(_caller_customer_id)
        WHERE id = _user_struct_id
    ) OR customers.is_user_deleted(_user_struct_id) THEN
        RAISE EXCEPTION 'No user_struct with id % found', _user_struct_id USING ERRCODE = 'T5AZ0';
    END IF;

        -- get enabled status
    SELECT customers.is_user_active(_user_struct_id) INTO _enabled;
    RAISE NOTICE 'enabled: %', _enabled;

        -- get role
    SELECT customers.role_build_json_ext(role_id, _caller_customer_id, NOT(_enabled))
    FROM customers.user_struct
    WHERE id = _user_struct_id
        INTO _role;

    -- get contacts
    SELECT ARRAY(
               SELECT customers.contact_get(id)
            FROM customers.contact
            WHERE user_struct_id = _user_struct_id
        ) INTO _contacts;

    -- get state
    SELECT INTO _state json_agg(x) -> 0 FROM (
        SELECT s.enabled, s.id, s.name
        FROM customers.user_state s
        INNER JOIN customers.user_struct u ON s.id = u.state_id
        WHERE u.id = _user_struct_id
        ) x;

    -- get biometric flag
    _is_biometric := customers.get_is_biometric(_user_struct_id);

        -- get latest biometric request (optional, can be null)
    BEGIN
            _latest_biometric_request := customers.get_latest_biometric_request(_user_struct_id);
    EXCEPTION WHEN OTHERS THEN
            _latest_biometric_request := NULL; -- if no request exists
    END;

        -- combine into single biometric_info object
        _biometric_info := json_build_object(
            'is_biometric', _is_biometric,
            'biometric_request', _latest_biometric_request
        );

        -- join in JSON
    SELECT INTO _res json_agg(x) -> 0 FROM (
        SELECT us.*,
        _role AS role,
        _contacts AS contacts,
        _state AS state,
        _biometric_info AS biometric
        FROM customers.user_struct us
        WHERE id = _user_struct_id
        LIMIT 1
        ) x;

    RETURN _res;

END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_build_json_sudo(_user_struct_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _role json;
    _contacts json[];
    _res json;
    _state json;
BEGIN

    -- get role
    SELECT customers.role_build_json_sudo(role_id) FROM customers.user_struct WHERE id = _user_struct_id INTO _role;

    -- get contacts
    SELECT ARRAY(
        SELECT customers.contact_get(id) FROM customers.contact WHERE user_struct_id = _user_struct_id
    ) INTO _contacts;

    -- state
    SELECT INTO _state json_agg(x) -> 0 FROM (
        SELECT s.enabled, s.id, s.name FROM customers.user_state s INNER JOIN customers.user_struct u ON s.id = u.state_id WHERE u.id = _user_struct_id
    )x;

    -- join in json
    SELECT INTO _res json_agg(x) -> 0 FROM (
        SELECT us.*, _role as role, _contacts as contacts, _state as state FROM customers.user_struct us WHERE id = _user_struct_id LIMIT 1
    ) x;

    RETURN _res;

END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_delete_ext(_user_struct_id bigint, _caller_customer_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    _email varchar;
BEGIN

    -- check if user_struct exists
    IF (NOT EXISTS(SELECT * FROM customers.user_struct_view_ext(_caller_customer_id) WHERE id = _user_struct_id)) OR ( customers.is_user_deleted(_user_struct_id)) THEN
        RAISE EXCEPTION 'No user_struct with id %d found', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- _email
    SELECT primary_email FROM customers.user_struct_view_ext(_caller_customer_id) WHERE id = _user_struct_id INTO _email;

    -- soft delete
    UPDATE customers.user_struct SET state_id = 4 WHERE id = _user_struct_id;

    PERFORM customers.anonymize_user_struct(_user_struct_id);

    -- check user (set new user_struct as active or delete user)
    RETURN customers.user_check(_email);
END;
$function$

