CREATE OR REPLACE FUNCTION customers.user_struct_get_all_ext(_caller_customer_id bigint, _search_string character varying)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_structs json[];
    _search_pattern varchar;
BEGIN

    SELECT concat('%', _search_string, '%') INTO _search_pattern;

    -- get all user_structs
    SELECT ARRAY(
                   SELECT customers.user_struct_build_json_ext(id, _caller_customer_id)
                   FROM customers.user_struct_view_ext(_caller_customer_id)
                   WHERE primary_email LIKE _search_pattern
                      OR first_name LIKE _search_pattern
                      OR last_name LIKE _search_pattern
                   ORDER BY last_name
           )
    INTO _user_structs;

    -- return
    RETURN to_json(_user_structs);

END;
$function$

