CREATE OR REPLACE FUNCTION customers.user_struct_get_current(_email character varying)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
    _user_struct_customer_id bigint;
BEGIN

    -- check user -> if true -> user has no user_structs and is deleted
    -- this should never happen, but better safe than sorry
    IF customers.user_check(_email) THEN
        RETURN '';
    end if;

    -- check if user exists
    IF NOT EXISTS (SELECT * FROM customers."user" WHERE email = _email) THEN
        RAISE EXCEPTION 'No user_struct with email % found', _email USING ERRCODE = 'T5AZ0';
    end if;

    -- check if any visible userstruct
    IF NOT EXISTS(SELECT * FROM customers.user_struct u INNER JOIN customers.user_state s on s.id = u.state_id WHERE s.visible_ext = true) THEN
        RAISE EXCEPTION 'No user_struct with email % found', _email USING ERRCODE = 'T5AZ0';
    end if;

    -- get active user struct id
    SELECT id FROM customers."user" u INNER JOIN customers.user_struct us ON u.active_user_struct_id = us.id WHERE email = _email INTO _user_struct_id;

    SELECT customer_id from customers.user_struct WHERE id = _user_struct_id INTO _user_struct_customer_id;

    -- return user_struct
    RETURN customers.user_struct_build_json_ext(_user_struct_id, _user_struct_customer_id);

END;
$function$

