CREATE OR REPLACE FUNCTION customers.user_struct_hard_delete_sudo(_user_struct_id bigint)
 RETURNS boolean
 LANGUAGE plpgsql
AS $function$
DECLARE
    _email varchar;
    _count int;
    _next bigint;
BEGIN

    -- check if user_struct exists
    IF NOT EXISTS(SELECT * FROM customers.user_struct WHERE id = _user_struct_id) THEN
        RAISE EXCEPTION 'No user_struct with id %d found', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- get email
    SELECT primary_email from customers.user_struct WHERE id = _user_struct_id INTO _email;


    IF EXISTS(SELECT * FROM "user" WHERE active_user_struct_id = _user_struct_id) THEN

        -- count
        SELECT INTO _count count(*) FROM customers.user_struct WHERE primary_email = _email;

        IF _count > 1 THEN

            -- get next
            SELECT INTO _next id FROM customers.user_struct WHERE primary_email = _email AND id <> _user_struct_id LIMIT 1;

            -- update
            UPDATE customers."user" SET active_user_struct_id = _next WHERE email = _email;

        ELSE

            -- update
            UPDATE customers."user" SET active_user_struct_id = NULL WHERE email = _email;
        END IF;

    END IF;

    -- delete contacts
    DELETE FROM customers.contact WHERE user_struct_id = _user_struct_id;

    -- delete
    DELETE FROM customers.user_struct WHERE id = _user_struct_id;

    -- check user (set new user_struct as active or delete user)
    RETURN customers.user_check(_email);

END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_new_ext(json_data json, _caller_customer_id bigint)
 RETURNS bigint
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
    _active_user_struct_id bigint;
    _contact json;
    _state_id bigint;
BEGIN

    -- check user_struct already exists
    IF EXISTS (SELECT * FROM customers.user_struct us WHERE primary_email = json_data ->> 'email' AND customer_id = _caller_customer_id) THEN
        RAISE EXCEPTION 'user_struct [% , %] already exists', json_data ->> 'email', json_data->>'customer_id' USING ERRCODE = 'T5AZ1';
    end if;

    -- check role exists
    IF NOT EXISTS (SELECT * FROM customers.role r WHERE id = (json_data ->> 'role_id')::bigint AND (customer_id = _caller_customer_id OR customer_id IS NULL)) THEN
        RAISE EXCEPTION 'No role with id % found', (json_data ->> 'role_id')::bigint USING ERRCODE = 'T3AZ0';
    end if;

    -- create user if not exists
    PERFORM customers.user_create_if_not_exists(json_data->>'email');

    IF json_data->>'state' IS NULL THEN
        _state_id = 1;
    else
        _state_id = (json_data->>'state')::bigint;
    end if;

    -- create user_struct
    INSERT INTO customers.user_struct (customer_id, primary_email, first_name, last_name, role_id, marketing_on_primary_email, maintenance_on_primary_email, state_id, phone) VALUES (
        _caller_customer_id, -- fixed to caller customer_id
        json_data->>'email',
        json_data->>'first_name',
        json_data->>'last_name',
        (json_data->> 'role_id')::bigint,
        (json_data->>'marketing_on_primary_email')::bool,
        (json_data->>'maintenance_on_primary_email')::bool,
        _state_id,
        json_data->>'phone'
    ) RETURNING id INTO _user_struct_id;

    -- update pointer to active struct if null
    SELECT active_user_struct_id FROM customers."user" WHERE email = json_data->>'email' INTO _active_user_struct_id;
    IF _active_user_struct_id IS NULL THEN
        UPDATE customers."user" SET active_user_struct_id = _user_struct_id WHERE email = json_data->>'email';
    end if;

    -- create contacts
    if (json_data ->> 'contacts') IS NOT NULL THEN

        for _contact in select * from json_array_elements(json_data -> 'contacts')
            loop

                PERFORM customers.user_struct_add_contact(_user_struct_id, _contact);
            end loop;
    END IF;

    RETURN _user_struct_id;
END;
$function$

