CREATE OR REPLACE FUNCTION customers.user_struct_set_current(_email character varying, _customer_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _user_struct_id bigint;
BEGIN

    -- check if user exists
    IF NOT EXISTS (SELECT * FROM customers."user" WHERE email = _email) THEN
        RAISE EXCEPTION 'No user_struct with email % found', _email USING ERRCODE = 'T5AZ0';
