        RAISE EXCEPTION 'No user_struct with email= % and customer_id= % found', _email, _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    -- get user struct id
    SELECT INTO _user_struct_id id FROM customers.user_struct WHERE primary_email = _email AND customer_id = _customer_id LIMIT 1;

    -- update
    UPDATE customers."user" SET active_user_struct_id = _user_struct_id WHERE email = _email;

END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_update_ext(json_data json, _caller_customer_id bigint)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    -- check if exist
    IF NOT EXISTS (SELECT * FROM customers.user_struct_view_ext(_caller_customer_id) WHERE id = (json_data ->> 'id')::bigint) THEN
        RAISE EXCEPTION 'No user_struct with id %d found', (json_data ->> 'id')::bigint USING ERRCODE = 'T5AZ0';
    end if;

    -- update role_id
    IF json_data ->> 'role_id' IS NOT NULL THEN

        IF NOT EXISTS(SELECT * FROM customers.role WHERE id = (json_data ->> 'role_id')::bigint AND (customer_id IS NULL or customer_id = _caller_customer_id)) THEN
            RAISE EXCEPTION 'No role with id %d found', (json_data ->> 'role_id')::bigint USING ERRCODE = 'T3AZ0';
        end if;
    END IF;

    PERFORM customers.user_struct_update_sudo(json_data);
END;
$function$

CREATE OR REPLACE FUNCTION customers.user_struct_update_sudo(json_data json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    _contact json;
    _user_struct customers.user_struct%rowtype;
BEGIN

    -- check if exist
    IF NOT EXISTS (SELECT * FROM customers.user_struct_view_cdlan() WHERE id = (json_data ->> 'id')::bigint) THEN
        RAISE EXCEPTION 'No user_struct with id %d found', (json_data ->> 'id')::bigint USING ERRCODE = 'T5AZ0';
    end if;

    SELECT * FROM customers.user_struct WHERE id = (json_data ->> 'id')::bigint INTO _user_struct;

    -- update updated field
    UPDATE customers.user_struct SET updated = NOW() WHERE id = (json_data ->> 'id')::bigint;

    -- update first_name
    IF json_data ->> 'first_name' IS NOT NULL THEN
        UPDATE customers.user_struct SET first_name = json_data ->> 'first_name' WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update language
    IF json_data ->> 'language' IS NOT NULL THEN
        UPDATE customers.user_struct SET language = json_data ->> 'language' WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update last_name
    IF json_data ->> 'last_name' IS NOT NULL THEN
        UPDATE customers.user_struct SET last_name = json_data ->> 'last_name' WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update state
    IF json_data ->> 'state' IS NOT NULL THEN
        UPDATE customers.user_struct SET state_id = (json_data ->> 'state')::bigint WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update phone
    IF json_data ->> 'phone' IS NOT NULL THEN
        UPDATE customers.user_struct SET phone = json_data ->> 'phone' WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update marketing_on_primary_email
    IF json_data ->> 'marketing_on_primary_email' IS NOT NULL THEN
        UPDATE customers.user_struct SET marketing_on_primary_email = (json_data ->> 'marketing_on_primary_email')::bool WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update maintenance_on_primary_email
    IF json_data ->> 'maintenance_on_primary_email' IS NOT NULL THEN
        UPDATE customers.user_struct SET maintenance_on_primary_email = (json_data ->> 'maintenance_on_primary_email')::bool WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- update role_id
    IF json_data ->> 'role_id' IS NOT NULL THEN

        IF NOT EXISTS(SELECT * FROM customers.role WHERE id = (json_data ->> 'role_id')::bigint) THEN
            RAISE EXCEPTION 'No role with id % found', (json_data ->> 'role_id')::bigint USING ERRCODE = 'T3AZ0';
        end if;

        IF NOT EXISTS(SELECT * FROM customers.role WHERE id = (json_data ->> 'role_id')::bigint AND (customer_id IS NULL or customer_id = _user_struct.customer_id)) THEN
            RAISE EXCEPTION 'role with id % cannot be assigned as it is not visible by user', (json_data ->> 'role_id')::bigint USING ERRCODE = 'T3AZ0';
        end if;

        UPDATE customers.user_struct SET role_id = (json_data ->> 'role_id')::bigint WHERE id = (json_data ->> 'id')::bigint;
    END IF;

    -- delete and replace contacts if specified
    if (json_data ->> 'contacts') IS NOT NULL THEN

        -- delete old
        DELETE FROM customers.contact WHERE user_struct_id = (json_data ->> 'id')::bigint;

        -- insert new
        for _contact in select * from json_array_elements(json_data -> 'contacts')
            loop

                PERFORM customers.user_struct_add_contact((json_data ->> 'id')::bigint, _contact);
            end loop;
    END IF;
END;
$function$

CREATE OR REPLACE FUNCTION customers.variable_add_to_customer(_customer_id bigint, _variable json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE

BEGIN
    -- create var if not exists
    IF NOT EXISTS(SELECT * FROM customers.variable WHERE resource = _variable->>'resource' AND action = _variable->>'action') THEN
        INSERT INTO customers.variable (resource, action) VALUES (_variable->>'resource', _variable->>'action');
    END IF;

    -- check if association already exists
    IF EXISTS(SELECT * FROM customers.customer_variable WHERE customer_id = _customer_id AND resource = _variable->>'resource' AND action = _variable->>'action') THEN
        RAISE EXCEPTION 'variable (%,%) already tied to customer %', _variable->>'resource', _variable->>'action', _customer_id  USING ERRCODE = 'T7AZ1';
    end if;

    -- insert
    INSERT INTO customers.customer_variable(customer_id, resource, action) VALUES (_customer_id, _variable->>'resource', _variable->>'action');
END;
$function$

CREATE OR REPLACE FUNCTION customers.variable_add_to_customer_group(_customer_group_id bigint, _variable json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE

BEGIN
    -- create var if not exists
    IF NOT EXISTS(SELECT * FROM customers.variable WHERE resource = _variable->>'resource' AND action = _variable->>'action') THEN
        INSERT INTO customers.variable (resource, action) VALUES (_variable->>'resource', _variable->>'action');
    END IF;

    -- check if association already exists
    IF EXISTS(SELECT * FROM customers.customer_group_variable WHERE customer_group_id = _customer_group_id AND resource = _variable->>'resource' AND action = _variable->>'action') THEN
        RAISE EXCEPTION 'variable (%,%) already tied to customer_group %', _variable->>'resource', _variable->>'action', _customer_group_id  USING ERRCODE = 'T7AZ1';
