$function$

CREATE OR REPLACE FUNCTION customers.variable_delete(_variable json)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

    IF NOT EXISTS(SELECT * FROM customers.variable WHERE action = _variable->>'action' AND resource = _variable->>'resource') THEN
        RAISE EXCEPTION 'No variable with (%, %) found', _variable->'resource', _variable->>'action' USING ERRCODE = 'T7AZ0';
    end if;

    DELETE FROM customers.variable WHERE action = _variable->>'action' AND resource = _variable->>'resource';
END;
$function$

CREATE OR REPLACE FUNCTION customers.variable_get_by_user_struct(_user_struct_id bigint)
 RETURNS json
 LANGUAGE plpgsql
AS $function$
DECLARE
    _customer_id bigint;
    _customer_group_id bigint;
BEGIN

    -- get customer id
    SELECT customer_id FROM customers.user_struct WHERE id = _user_struct_id INTO _customer_id;

    IF _customer_id IS NULL THEN
        RAISE EXCEPTION 'No user_struct with id %d found', _user_struct_id USING ERRCODE = 'T5AZ0';
    end if;

    IF (SELECT cs.enabled FROM customers.customer_state cs INNER JOIN customers.customer c on cs.id = c.state_id WHERE c.id = _customer_id) THEN

        SELECT group_id FROM customers.customer WHERE id = _customer_id INTO _customer_group_id;

        RETURN json_agg(x) FROM (
            (SELECT resource, action FROM customers.customer_variable WHERE customer_id = _customer_id)
            UNION
            (SELECT resource, action FROM customers.customer_group_variable WHERE customer_group_id = _customer_group_id)
        ) x;
    ELSE

        return NULL;
    end if;

END;
$function$
